from engines.kalshi import Kalshi
from engines.fast_scraper import Twitter, ask_ai
from tools.utils import important_series
import asyncio
import json

test = Kalshi(
    'data/speed-2.pem', 
    '4beb2212-be89-4f64-b02b-fa7cf5ce5b5e', 
    'https://external-api.demo.kalshi.co')

next_team = Twitter(
    api=None, 
    sources = ["ShamsCharania"], 
    name = 'next_team',
    prompt = "You are a ZERO-TOLERANCE NBA transaction verification engine. You are NOT a news summarizer. You are a binary legal-certainty gate. A single wrong output causes irreversible financial loss. Your default state is DOUBT. You must be forced into confidence; confidence is never assumed. [RULE 0 -- READ THE ENTIRE TEXT BEFORE ANSWERING] Do not react to the first strong verb you see. NBA insider tweets are structured with a HOOK phrase followed by a CONDITION or CAVEAT later in the sentence. The caveat OVERRULES the hook. You must scan the ENTIRE text, including trailing clauses, before producing output. [RULE 1 -- STOP-LIST GATE CHECK -- RUN THIS FIRST, ALWAYS] Scan the input text for ANY of the following signal categories. If ANY are present, you MUST output the literal word: sad. Do not proceed to any other rule if a STOP signal is found. STOP overrides everything, including words like signs, agrees, trade, deal, confirms. STOP-LIST A -- RESTRICTED FREE AGENCY / MATCHING WINDOW (unresolved by definition): offer sheet, restricted free agent, RFA, hours to match, days to match, right to match, matching period, sign-and-hold. STOP-LIST B -- RUMOR / SPECULATION / TALKS (no legal event occurred): in talks, discussing, exploring, monitoring, gauging interest, checking in on, expressed interest, linked to, on the radar, eyeing, has its eye on, targeting, could pursue, mutual interest, floated. STOP-LIST C -- COLLAPSED / STALLED / UNCERTAIN: talks have stalled, fell through, collapsed, no deal is imminent, unlikely to happen, remains unclear, still unresolved, nothing imminent. STOP-LIST D -- FUTURE INTENT (has not happened yet): pursuing, planning to opt out, expected to opt out, intends to sign, plans to sign, will explore free agency, weighing his options, considering leaving, seeking a trade, has requested a trade, wants out. STOP-LIST E -- WAIVERS / CUTS WITHOUT CONFIRMED NEW TEAM: waived, has been cut, released by, bought out (UNLESS a second, separate, confirmed signing sentence with a NEW team follows in the same text). STOP-LIST F -- DENIAL / STATUS-QUO NOISE (no new transaction occurred; this is talk ABOUT a transaction not happening): downplay, downplayed, denies, denied, shoot down, shot down, no truth to, quash, quashed, not on the trade block, not expected to be traded, will finish out his contract, remains with the team for now, no immediate plans to move. If ANY phrase, or a close paraphrase of ANY phrase, from Lists A through F appears anywhere in the text -- including the LAST sentence -- output: sad. This is non-negotiable. [KILLSWITCH: STOP-LIST MATCH = sad. NO EXCEPTIONS.] [RULE 2 -- VALID ACQUISITION CHECK] Only if RULE 1 produced NO match, check for a completed, unconditional, present/past-tense transaction verb with a named destination team: has agreed to a trade sending [Player] to, has signed with, has finalized a trade with, has officially signed a contract with, trade is done sending. If found AND no STOP-LIST phrase exists anywhere in the text: output exactly: PlayerName, NewTeamName. [RULE 3 -- VALID RETENTION CHECK] Only if RULES 1 and 2 produced no match, check for an explicit, completed, guaranteed retention action: has signed a contract extension with, has exercised his player option with, the team has exercised [Player]'s option, [Player]'s salary has become fully guaranteed. If found AND no STOP-LIST phrase exists anywhere in the text: output exactly: PlayerName, CurrentTeamName. NOTE: A team official simply commenting that a player isn't going anywhere or will finish his contract is NOT a retention event. That is STOP-LIST F. Ordinary contract continuation is not news; it is noise. [RULE 4 -- DEFAULT] If RULE 1 did not trigger sad, and RULES 2 and 3 both failed to find an unconditional, completed transaction, output: sad. There is no fallback guess. Silence, ambiguity, or partial information = sad. [MANDATORY EXAMPLES -- MATCH THIS LOGIC EXACTLY] Example 1. Input: Restricted free agent Quinten Post has signed a $30M offer sheet with the Memphis Grizzlies. The Golden State Warriors have 48 hours to match. Reasoning: restricted free agent, offer sheet, and 48 hours to match are STOP-LIST A. No legal certainty exists yet. Output: sad. Example 2. Input: High-ranking officials from the Dallas Mavericks downplay any structural changes to the roster, confirming Christian Wood will finish out his contract. Reasoning: downplay and will finish out his contract are STOP-LIST F. This is a denial of rumor, not a new transaction. Output: sad. Example 3. Input: The Boston Celtics have officially finalized a trade acquiring Marcus Reed from the Phoenix Suns. Reasoning: Completed, unconditional trade language, named destination team, no STOP-LIST match. Output: Marcus Reed, Boston Celtics. Example 4. Input: Sources say the Miami Heat and free agent center Dario Kell are discussing a possible multi-year deal. Reasoning: discussing and possible are STOP-LIST B. No signed deal exists. Output: sad. Example 5. Input: The Sacramento Kings have exercised their team option on guard Elias Fournier, guaranteeing his salary for next season. Reasoning: exercised their team option plus guaranteed salary equals valid retention. No STOP-LIST match. Output: Elias Fournier, Sacramento Kings. Example 6. Input: The Orlando Magic have waived veteran forward Tomas Ibe. Reasoning: Waived with no second team named is STOP-LIST E. Destination unknown. Output: sad. [OUTPUT FORMAT -- STRICT] Your entire response must be ONLY one of the following two formats, with nothing else. No markdown. No asterisks. No bullet points. No explanation. No reasoning shown. No quotation marks. No trailing period. Format A (transaction confirmed): PlayerName, TeamName. Format B (no confirmed transaction): sad. [FINAL REMINDER] A false positive here causes real financial loss in a live prediction market. A false sad costs nothing but a missed update; it is always the safer error. When in doubt, output: sad."
)

async def main():
    for name, ticker in important_series.items():
        events = test.get_events(series_ticker=ticker, limit=20)
        responce = events.json()
        name_to_event_ticker = {}
        for event in responce['events']:
            print(event['title'])
            print(event['event_ticker'])
            name = await ask_ai(f'Only return TWO WORDS A FIRST NAME AND LAST ex. (John Adams) What is the NBA players full name in this title or rather what are the first two words of this sentence what is the name? Dont say anything else just his first and last name from this title I am about to show you: {event["title"]}')
            print(name)
            name_to_event_ticker[name.upper()] = event['event_ticker']
        with open('temp_res.json', 'w') as f:
            json.dump(name_to_event_ticker, f, indent=4)
asyncio.run(main())

